const body = JSON.parse($input.first().json.content[0].text);
if (body.error) throw new Error('No entendido');

const today = new Date().toISOString().split('T')[0];
const transaction = {
  id: Date.now().toString(36) + Math.random().toString(36).slice(2,7),
  type: body.type,
  category: body.category,
  amount: parseFloat(body.amount),
  description: body.description || '',
  date: body.date || today,
  createdAt: new Date().toISOString(),
  source: 'telegram'
};
return [{ json: transaction }];

const fileData = $('GitHub - Leer transactions.json').first().json;
const newTransaction = $('Parsear transacción').first().json;

const decoded = Buffer.from(fileData.content.replace(/\n/g, ''), 'base64').toString('utf-8');
const transactions = JSON.parse(decoded);
transactions.unshift(newTransaction);

const encoded = Buffer.from(JSON.stringify(transactions, null, 2)).toString('base64');
return [{ json: { content: encoded, sha: fileData.sha, transaction: newTransaction } }];

